// Raw pet templates moved to ./data/pet-pool; the balancer scales each
// template against the global stat caps before it goes into petPool.
const petPool: Pet[] = rawPetPool.map(balanceBuiltInPetTemplate);

function mergeMissingBuiltInPets(currentPets: Pet[]): Pet[] {
    const currentIds = new Set(currentPets.map((pet) => pet.id));
    const missingBuiltInPets = petPool.filter((pet) => !currentIds.has(pet.id));

    return [...currentPets, ...missingBuiltInPets];
}
// cloneEncounterPet + builtInPetTemplateId moved to ./lib/pet-balance.
function normalizePet(pet: Pet): Pet {
    const baseTemplate = petPool.find((template) => template.id === builtInPetTemplateId(pet.id));
    const merged = baseTemplate ? {
        ...pet,
        hp: Math.max(pet.hp ?? 0, baseTemplate.hp),
        attack: Math.max(pet.attack ?? 0, baseTemplate.attack),
        defense: Math.max(pet.defense ?? 0, baseTemplate.defense),
        speed: Math.max(pet.speed ?? 0, baseTemplate.speed),
        moveRange: pet.moveRange ?? baseTemplate.moveRange,
        // Backfill element from the template for existing saves whose pets
        // predate the element field. Pet's own element (if any) wins so a
        // future admin-edit override would still stick.
        element: pet.element ?? baseTemplate.element,
        // Backfill any NEW jutsu slots the template gained since this save
        // was written (e.g. the elemental special jutsu added later). We
        // iterate up to the larger of the two arrays and fall back to the
        // template entry for any slot the player's save doesn't have.
        jutsus: (() => {
            const playerJutsus = pet.jutsus ?? [];
            const maxLen = Math.max(playerJutsus.length, baseTemplate.jutsus.length);
            return Array.from({ length: maxLen }, (_, i) => {
                const baseJutsu = baseTemplate.jutsus[i];
                const playerJutsu = playerJutsus[i];
                if (!playerJutsu && baseJutsu) {
                    // Slot is new — copy straight from the template.
                    return { ...baseJutsu, currentCooldown: 0 };
                }
                return {
                    ...(baseJutsu ?? {}),
                    ...playerJutsu,
                    power: Math.max(playerJutsu?.power ?? 0, baseJutsu?.power ?? 0),
                    currentCooldown: 0,
                };
            });
        })(),
    } : pet;
    return capPetStats({
        ...merged,
        rarity: merged.rarity ?? "standard",
        level: Math.max(1, Math.floor(merged.level ?? 1)),
        xp: Math.max(0, Math.floor(merged.xp ?? 0)),
        maxLevel: Math.max(1, Math.floor(merged.maxLevel ?? 100)),
        unlockedForPve: Boolean(merged.unlockedForPve || Math.floor(merged.level ?? 1) >= 50),
        happiness: petHappiness(merged),
        expedition: merged.expedition
            ? { type: merged.expedition.type ?? "scout", startedAt: Number(merged.expedition.startedAt ?? Date.now()), endsAt: Number(merged.expedition.endsAt), durationMs: Number(merged.expedition.durationMs ?? 60 * 60 * 1000) }
            : undefined,
    });
}
